  faq_intro = 'Key questions about AI deployment for Governance, Risk and Compliance.'
WHERE variant_id = 89;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Production AI deployment', 'Validated AI models live in your environment, connected to GRC data sources, and processing alerts within agreed latency and accuracy thresholds.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Guardrails and safety controls documentation', 'Configured human-in-the-loop checkpoints, override procedures, and escalation paths documented for audit and regulatory review.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Monitoring and performance dashboard', 'Real-time view of model outputs, alert volumes, false-positive rates, and compliance outcomes with configurable thresholds and alerting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (89, 'Operations and retraining guide', 'Step-by-step procedures for your GRC team to manage model performance, trigger retraining, and document decisions for audit purposes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'What AI use cases can you put into production for GRC?', 'Continuous control monitoring, transaction anomaly detection, regulatory change classification, and AI-assisted policy review are the most common production deployments. The DigitalQatalyst team works from your validated AI design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'How do you ensure the AI does not make compliance decisions without human review?', 'Human-in-the-loop checkpoints are configured before deployment. High-risk alerts always route to a named reviewer before any action is taken. Guardrail logic is documented and auditable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'What happens if model accuracy degrades after go-live?', 'The monitoring dashboard surfaces accuracy metrics weekly. The operations guide includes retraining triggers and the DigitalQatalyst team provides hypercare support during the first two weeks post-launch.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'Do we need a deployment specification before this engagement?', 'Yes, the AI Deploy engagement builds from the specifications produced in an AI Design phase. If those are not in place, the DigitalQatalyst team can scope a combined design and deployment programme.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (89, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm readiness, environment requirements, and the deployment timeline within one week.', 4);

-- Governance, Risk & Compliance (High-Impact) - Managed (variant 90)
UPDATE product_content SET
  description = 'Keep your GRC capability operating at peak performance with ongoing monitoring, control testing, compliance reporting, and continuous optimisation backed by a named DigitalQatalyst team and defined service levels.',
  positioning = 'Ongoing GRC operations with named accountability: monthly reporting, continuous control testing, and proactive optimisation.',
  hero_summary = 'Keep your GRC capability operating at peak performance with ongoing monitoring, control testing, compliance reporting, and continuous optimisation backed by a named DigitalQatalyst team and defined service levels.',
  overview_paragraphs = '["The Governance, Risk & Compliance Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve governance, risk and compliance with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for risk, compliance, audit & legal leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for governance, risk & compliance - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Named DigitalQatalyst team with defined response SLAs across all service tiers","Monthly board-ready compliance reports and quarterly audit evidence packs included","Proactive regulatory change monitoring so you are not caught off-guard by new obligations"]'::jsonb,
  why_it_matters = '{"hook":"Governance and compliance are not overhead, they are what makes sustainable transformation possible.","problemParagraph":"Many organisations struggle to sustain performance across your GRC programme after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"governance, risk & compliance issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Governance, Risk and Compliance managed service.'
WHERE variant_id = 90;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Monthly compliance performance reports', 'Structured reports covering control status, open exceptions, remediation progress, and framework compliance score, formatted for board and audit committee use.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Quarterly control testing evidence packs', 'Documented test results for in-scope controls, suitable for internal audit review and external certification bodies.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Exception and incident log', 'Running record of control exceptions, incidents, and remediation actions with timestamps and owner details for regulatory and audit purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (90, 'Optimisation recommendations', 'Quarterly recommendations for control improvements, tooling adjustments, or process changes based on performance data and regulatory developments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'What is included in the monthly service?', 'Continuous control monitoring, exception alerting, a compliance performance report, and ongoing liaison with your risk and audit teams. Quarterly deliverables include control testing and evidence packs.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How quickly do you respond to a control failure or incident?', 'Response times depend on your service tier. Critical control failures are escalated within four hours. The DigitalQatalyst team confirms SLA thresholds during onboarding.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'Can the service scale if our regulatory obligations change?', 'Yes. The engagement is reviewed quarterly. New frameworks, expanded scope, or additional controls can be added through a change request without restarting the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How does the service handle a regulator audit or certification visit?', 'The DigitalQatalyst team prepares and packages evidence for the audit scope, attends readiness reviews, and supports your team throughout the audit process as part of the managed service.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (90, 'How do we get started?', 'The DigitalQatalyst team runs a two-week onboarding to establish baselines, confirm SLAs, and connect monitoring tooling before steady-state operations begin.', 4);

-- Enterprise Resource Planning (High-Impact) - Assess (variant 91)
UPDATE product_content SET
  description = 'Understand exactly where your ERP is creating manual workarounds, data quality problems, and integration failures across finance, procurement, and HR, then get a prioritised remediation roadmap your leaders can act on, all within one week.',
  positioning = 'Understand exactly where your ERP is creating manual workarounds and data quality issues, and get a sequenced plan to fix them.',
  hero_summary = 'Understand exactly where your ERP is creating manual workarounds, data quality problems, and integration failures across finance, procurement, and HR, then get a prioritised remediation roadmap your leaders can act on, all within one week.',
  overview_paragraphs = '["The Enterprise Resource Planning Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps ERP maturity and returns prioritised improvements your finance and operations leaders can act on.","See how ERP and core enterprise operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews enterprise resource planning across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed scope covering your agreed ERP modules -- no unbounded discovery and no access required beyond read-only system review","Finance, procurement, and HR modules assessed in an integrated review, not separately","Data risk flags included so finance leaders understand where ERP gaps create reporting exposure"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many organisations run ERP landscapes with misaligned modules, master data issues, and unclear upgrade or replacement paths. This assessment maps ERP maturity and returns prioritised improvements your finance and operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Master data inconsistency","description":"Finance and operations teams work from conflicting item, vendor, and customer records."},{"title":"Process misalignment","description":"Core workflows do not match how business units actually operate."},{"title":"Upgrade uncertainty","description":"Technical debt and customisation risk obscure the right modernisation path."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"ERP maturity view","description":"Leadership sees where data, process, and platform readiness stand today."},{"title":"Prioritised roadmap","description":"Initiatives are ordered by business impact, risk, and dependency."},{"title":"Investment clarity","description":"Your leaders can fund stabilisation, optimisation, or transformation first."}]}}'::jsonb,
  faq_intro = 'Questions about the ERP assessment engagement.'
WHERE variant_id = 91;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'ERP Process Coverage Assessment', 'Module-by-module review of finance, procurement, HR, and inventory processes showing where ERP covers the business need and where manual workarounds have filled the gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Data Quality Report', 'Assessment of master data accuracy, transactional data completeness, and reporting consistency, with specific data domains flagged for remediation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Integration Gap Analysis', 'Documented review of data flows between ERP and connected systems, with gaps, duplications, and reconciliation failures identified and ranked by financial risk.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (91, 'Prioritised Remediation Roadmap', 'Sequenced improvement plan covering ERP configuration, data remediation, and integration fixes, with effort estimates and ownership assignments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Which ERP platforms does the assessment cover?', 'SAP, Oracle, Microsoft Dynamics 365, and Sage are the primary platforms covered. If your environment runs a different ERP, confirm with the DigitalQatalyst team during scoping -- most mid-market platforms can be assessed using the same methodology.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Can you assess an ERP that is heavily customised?', 'Yes. Customised ERPs are a common source of the gaps this assessment finds. The review covers both standard module gaps and the technical debt from custom development.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'Do you need access to the ERP system itself?', 'Read-only access to the system and sample data extracts is helpful. The assessment can also run on documentation and stakeholder interviews if system access is restricted.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (91, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm the modules in scope, the stakeholders to involve, and any documentation or data extracts to prepare in advance.', 3);

-- Enterprise Resource Planning (High-Impact) - Design (variant 92)
UPDATE product_content SET
  description = 'Design your ERP improvements properly before configuration begins: redesigned process flows, data model specifications, and configuration blueprints your implementation team can build against, covering finance, procurement, and HR modules, across a four-week engagement.',
  positioning = 'Design your ERP improvements properly before configuration begins: fewer change requests, fewer reconciliation failures, and a system that reflects how your business actually runs.',
  hero_summary = 'Design your ERP improvements properly before configuration begins: redesigned process flows, data model specifications, and configuration blueprints your implementation team can build against, covering finance, procurement, and HR modules, across a four-week engagement.',
  overview_paragraphs = '["The Enterprise Resource Planning Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines ERP workflows and build-ready specifications.","Turn ERP and core enterprise operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate enterprise resource planning requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Master data model designed alongside process, preventing the data quality issues that derail ERP go-lives","Configuration blueprint formatted for direct use by your ERP implementation team","Integration architecture included so downstream systems are part of the design from the start"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many organisations configure ERP without designed process models, data standards, or specifications functional teams can implement. This design engagement defines ERP workflows and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined process templates","description":"Order-to-cash, procure-to-pay, and record-to-report paths lack standard design."},{"title":"Data model gaps","description":"Chart of accounts, items, and dimensions lack governance and ownership."},{"title":"Build ambiguity","description":"Functional and technical teams lack specs for configuration and integration."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned ERP processes","description":"Workflows reflect how finance and operations need to run at scale."},{"title":"Consistent data standards","description":"Master data and integration rules are defined upfront."},{"title":"Implementation-ready specs","description":"Teams receive artefacts that reduce rework during ERP delivery."}]}}'::jsonb,
  faq_intro = 'Questions about the ERP design engagement.'
WHERE variant_id = 92;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'ERP Process Design Documents', 'To-be process flows for each in-scope ERP module covering every transaction type, approval path, exception, and reporting touchpoint.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'Master Data Standards Specification', 'Defined standards for chart of accounts, cost centres, supplier master, and employee data, with ownership rules and data quality criteria.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'ERP Configuration Blueprint', 'Module-level configuration specifications covering settings, approval workflows, validation rules, and reporting dimensions your ERP team can implement directly.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (92, 'Integration Architecture Document', 'Data flow diagrams and API specifications for connections between ERP and payroll, CRM, data warehouse, and other dependent systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'How many ERP modules does the design engagement cover?', 'Scope is agreed at the start of week one. Most engagements cover three to five modules. Finance, procurement, and HR are the most common combination.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'Does this produce artefacts that an SAP or Oracle implementer can use directly?', 'Yes. Configuration blueprints are produced in a format aligned to the conventions of your target platform. The DigitalQatalyst team confirms the artefact format at kickoff.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'Can you help with the chart of accounts redesign specifically?', 'Yes. Chart of accounts and cost centre structure redesign is a standard workstream within the master data specification deliverable.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (92, 'How do we get started?', 'Share your ERP assessment findings or a summary of the improvements needed and the DigitalQatalyst team will confirm scope, module coverage, and the week-one workshop schedule.', 3);

-- Enterprise Resource Planning (High-Impact) - AI Design (variant 93)
UPDATE product_content SET
  description = 'Make your ERP data work harder for finance, procurement, and HR decision-makers by identifying where AI can improve ERP-driven decisions, from automated invoice matching and cash flow forecasting to procurement risk detection, with responsible design and governance specifications for each validated use case.',
  positioning = 'Design the AI capabilities that make your ERP data work harder for finance, procurement, and HR decision-makers.',
  hero_summary = 'Make your ERP data work harder for finance, procurement, and HR decision-makers by identifying where AI can improve ERP-driven decisions, from automated invoice matching and cash flow forecasting to procurement risk detection, with responsible design and governance specifications for each validated use case.',
  overview_paragraphs = '["The Enterprise Resource Planning AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for ERP and core enterprise operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for enterprise resource planning.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Finance-specific control framework designed for every AI use case, not a generic responsible AI checklist","ERP data readiness assessed before build investment is committed","Auditability requirements designed in from the start to satisfy finance audit and regulatory review"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many organisations apply AI to your ERP landscape without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for enterprise resource planning lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for enterprise resource planning are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about designing AI capabilities for ERP environments.'
WHERE variant_id = 93;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP AI Use-Case Assessment', 'Scored list of AI opportunities across finance, procurement, and HR, ranked by financial impact, data readiness, and audit risk.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP Data Readiness Report', 'Assessment of transactional and master data quality, volume, and lineage against the requirements for each AI candidate, with remediation steps for gaps.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'Responsible AI Specifications for Finance Contexts', 'Control framework and audit trail requirements for each AI use case, designed to satisfy finance audit, SOX, and regulatory scrutiny.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (93, 'ERP AI Integration Specifications', 'Detailed API and data flow designs for embedding AI recommendations, alerts, and automated actions within ERP workflows.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'Which AI use cases are most mature for ERP environments?', 'Accounts payable matching, invoice exception detection, cash flow forecasting, and spend category classification are the most commonly deployed. The DigitalQatalyst team validates which are appropriate for your ERP data and processes.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'How do you address the audit trail requirements for AI-driven financial decisions?', 'Every AI action in a finance context is designed with a full audit record: the input data, model version, output, confidence score, and any human review action. This is specified in the control framework deliverable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'Can AI work with the data quality we currently have in our ERP?', 'The data readiness report will tell you clearly. Some use cases are feasible with targeted remediation; others require a data quality programme first. The DigitalQatalyst team will not recommend AI deployment on data that does not meet minimum quality thresholds.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (93, 'How do we get started?', 'Contact the DigitalQatalyst team with your ERP platform details and the finance processes you are considering for AI. They will confirm the use-case discovery scope and week-one workshop participants.', 3);

-- Enterprise Resource Planning (High-Impact) - Deploy (variant 94)
UPDATE product_content SET
  description = 'Get your ERP modules correctly configured, your data migrated cleanly, and your finance and procurement teams live on improved processes, with structured data migration, business user testing, and handover to your finance and IT teams, all within twelve weeks.',
  positioning = 'Get your ERP configured correctly, your data migrated cleanly, and your finance and procurement teams live on improved processes within twelve weeks.',
  hero_summary = 'Get your ERP modules correctly configured, your data migrated cleanly, and your finance and procurement teams live on improved processes, with structured data migration, business user testing, and handover to your finance and IT teams, all within twelve weeks.',
  overview_paragraphs = '["The Enterprise Resource Planning Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed ERP and core enterprise operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated enterprise resource planning assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Month-end close rehearsal in user acceptance testing confirms finance teams are ready before go-live","Parallel run period included to reduce financial reporting risk at cutover","Go-live operations pack hands operational control to your finance and IT teams cleanly"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many organisations stall between approved designs and production for your ERP landscape, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for enterprise resource planning sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the ERP deployment engagement.'
WHERE variant_id = 94;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Configured ERP Modules', 'Finance, procurement, and HR modules live in production, configured to the approved specification and accepted by business module owners.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Migrated and Reconciled Data', 'Master data and opening balances loaded to production with reconciliation evidence confirming accuracy against the source system.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Integration Connections with Test Evidence', 'Functioning and documented data flows between ERP and connected systems, with executed test scripts and business sign-off records.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (94, 'Go-Live Operations Pack', 'Cutover runbook, rollback procedure, period-end close checklist, and administrator guide for your finance and IT teams to manage the post-go-live environment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'How do you handle the cutover from our current ERP to the new configuration?', 'The DigitalQatalyst team designs a detailed cutover plan in weeks eleven to twelve, including a parallel run period, a reconciliation checklist, and a rollback procedure if issues arise post-go-live.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'What if data quality issues are discovered during migration?', 'Migration runs in weeks three to eight surface data quality issues before the production load. The DigitalQatalyst team works with your data owners to resolve issues and re-run migration before user acceptance testing begins.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'Can we run the ERP deployment while the business continues normal operations?', 'Yes. The programme is designed to run alongside business operations. The cutover is timed to minimise disruption to financial period-end activities.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (94, 'How do we get started?', 'Provide your approved ERP design specification and the DigitalQatalyst team will confirm environment access, data migration scope, and the sprint-one schedule with your finance and IT leads.', 3);

-- Enterprise Resource Planning (High-Impact) - AI Deploy (variant 95)
UPDATE product_content SET
  description = 'Deploy AI into your ERP environment with the audit trail, control framework, and accuracy monitoring your finance function requires, covering automated invoice processing, cash flow forecasting, and spend anomaly detection, active from the pilot phase.',
  positioning = 'Deploy AI into your ERP with the audit trail, control framework, and accuracy monitoring your finance function requires.',
  hero_summary = 'Deploy AI into your ERP environment with the audit trail, control framework, and accuracy monitoring your finance function requires, covering automated invoice processing, cash flow forecasting, and spend anomaly detection, active from the pilot phase.',
  overview_paragraphs = '["The Enterprise Resource Planning AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled ERP and core enterprise operations workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for enterprise resource planning with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot phase validates invoice matching accuracy before full AP volume runs through the AI","Finance-grade audit logging active from day one, covering every AI decision","Cash flow forecasting includes variance explanations so finance teams can interrogate AI outputs"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many AI initiatives for your ERP landscape fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for enterprise resource planning fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about deploying AI into ERP environments.'
WHERE variant_id = 95;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Deployed Invoice Matching Automation', 'AI-powered three-way match running in your ERP accounts payable workflow, with agreed accuracy rates achieved during pilot before full production rollout.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Cash Flow Forecasting Integration', 'Rolling cash flow forecast generated from live ERP data, displayed within the finance team''s planning environment with variance explanations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Spend Anomaly Detection Alerts', 'Configured alert rules detecting policy breaches and spending pattern anomalies, routed to the appropriate procurement or finance approver.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (95, 'Finance-Grade Audit Log and Control Report', 'Complete audit trail for every AI decision during the deployment period, reviewed against the control framework and cleared for finance audit.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'What invoice matching accuracy rates can we expect?', 'Straight-through processing rates depend on invoice quality and supplier data consistency. The DigitalQatalyst team sets accuracy targets during the pilot and does not proceed to full rollout until they are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'How does AI cash flow forecasting work alongside our existing treasury models?', 'The AI forecast runs as a complementary input, not a replacement for treasury models. The integration design confirms how the two outputs are presented to the finance team.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'Can the AI be switched off for a specific invoice type or supplier without affecting everything else?', 'Yes. Inclusion rules are configured at a granular level so the finance team can exclude specific transaction types, suppliers, or currency categories from AI processing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (95, 'How do we get started?', 'Share your AI design specifications and ERP environment details with the DigitalQatalyst team. They will confirm data pipeline prerequisites and the pilot cohort before work begins.', 3);

-- Enterprise Resource Planning (High-Impact) - Managed (variant 96)
UPDATE product_content SET
  description = 'Ongoing managed operations for your ERP environment and AI capabilities, covering system health monitoring, period-end support, data quality governance, and monthly performance reporting so your finance and procurement functions run without operational disruption.',
  positioning = 'Keep your ERP and finance AI capabilities running reliably, with expert support for period-end close and proactive monitoring between reporting cycles.',
  hero_summary = 'Ongoing managed operations for your ERP environment and AI capabilities, covering system health monitoring, period-end support, data quality governance, and monthly performance reporting so your finance and procurement functions run without operational disruption.',
  overview_paragraphs = '["The Enterprise Resource Planning Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve ERP and core enterprise operations with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cfos, finance, procurement & hr leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for enterprise resource planning - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Period-end close support included as standard, not an additional call-off","AI model accuracy reviewed monthly and recalibrated before drift affects financial reporting","ERP patch impact assessments prevent unplanned disruption to finance operations"]'::jsonb,
  why_it_matters = '{"hook":"Your ERP connects finance, operations, and supply chain, making it foundational to organisational performance.","problemParagraph":"Many organisations struggle to sustain performance across your ERP landscape after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"enterprise resource planning issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the ERP managed service.'
WHERE variant_id = 96;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'Monthly ERP Health and AI Performance Report', 'System uptime, integration health, data quality metrics, AI model accuracy, and SLA adherence, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'Period-End Close Support Log', 'Record of every issue identified and resolved during monthly and quarterly period-end close, with root cause and prevention measure for recurring issues.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'AI Model Accuracy Review', 'Monthly comparison of invoice matching and forecasting accuracy against agreed thresholds, with recalibration actions taken and the next review date.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (96, 'ERP Change Impact Assessment', 'Assessment of every planned ERP patch, upgrade, or configuration change for impact on processes, integrations, and AI data pipelines, with a test plan and implementation recommendation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'What does period-end close support actually cover?', 'The DigitalQatalyst team is available during month-end and quarter-end windows to assist with reconciliation checks, posting run monitoring, and rapid resolution of system issues that arise during the close process.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'How do you manage ERP patches without disrupting production?', 'Every patch is assessed for impact, tested in a non-production environment, and approved by your finance IT lead before it is applied to production. Testing covers integration connections and AI data pipelines.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'What happens if an AI model starts producing inaccurate invoice matches?', 'The monthly accuracy review will identify the drift. The DigitalQatalyst team implements recalibration and, where necessary, initiates retraining. You are notified before any threshold breach affects your AP processing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (96, 'How do we get started?', 'Contact the DigitalQatalyst team with your current ERP and AI configuration documentation. They will complete a health baseline audit before the first SLA period begins.', 3);

-- Workforce Management (High-Impact) - Assess (variant 97)
UPDATE product_content SET
  description = 'Understand where your workforce management platform is falling short: scheduling gaps, visibility blind spots, and coordination friction that cost you productivity every day. The DigitalQatalyst team returns a prioritised findings report and a practical roadmap your HR and operations leaders can act on immediately.',
  positioning = 'A structured assessment that shows exactly where workforce management breaks down and what to fix first.',
  hero_summary = 'Understand where your workforce management platform is falling short: scheduling gaps, visibility blind spots, and coordination friction that cost you productivity every day. The DigitalQatalyst team returns a prioritised findings report and a practical roadmap your HR and operations leaders can act on immediately.',
  overview_paragraphs = '["The Workforce Management Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps workforce maturity and returns prioritised improvements your HR and operations leaders can act on.","See how workforce management performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for hr, workforce planning & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews workforce management across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment with no obligation to proceed","Covers distributed, shift-based, field, and frontline workforce models","Findings delivered within one week"]'::jsonb,
  why_it_matters = '{"hook":"Workforce systems shape how you deploy talent, manage capacity, and respond to demand.","problemParagraph":"Many organisations manage workforce planning with disconnected HR, scheduling, and payroll systems and limited visibility into capacity risk. This assessment maps workforce maturity and returns prioritised improvements your HR and operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Siloed workforce data","description":"Scheduling, skills, and attendance live in systems that do not reconcile."},{"title":"Capacity blind spots","description":"Leaders cannot forecast demand against available skills and hours."},{"title":"Compliance risk","description":"Labour rules and roster policies are applied inconsistently."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Workforce priority map","description":"You know which processes, data, and platforms to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, integration, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and workforce funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the workforce management assessment.'
WHERE variant_id = 97;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Workforce maturity scorecard', 'Ratings across scheduling accuracy, labour visibility, coordination tools, and compliance controls, with evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Gap and friction register', 'Documented breakdowns in scheduling, attendance tracking, and cross-team coordination, ranked by business impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Prioritised improvement roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies so your team knows what to tackle first.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (97, 'Stakeholder briefing pack', 'A concise summary of findings and recommended investment for HR, finance, and operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'What workforce models does this cover?', 'Distributed, shift-based, field, frontline, and knowledge worker models. The DigitalQatalyst team confirms which apply to your organisation during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'Do you need access to our scheduling or HR systems?', 'We review configuration and reporting outputs rather than live data. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'What do we get at the end?', 'A maturity scorecard, a gap and friction register, a prioritised improvement roadmap, and a stakeholder briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'How long does the assessment take?', 'One week from kick-off to findings delivery, assuming stakeholders are available for interviews in the first two days.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (97, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, workforce categories in scope, and key stakeholders before work begins.', 4);

-- Workforce Management (High-Impact) - Design (variant 98)
UPDATE product_content SET
  description = 'Turn workforce management goals into a complete, build-ready blueprint: role-based journeys, scheduling logic, integration specifications, and an adoption plan your delivery teams can execute without ambiguity.',
  positioning = 'A design engagement that produces workforce management specifications ready for configuration and build.',
  hero_summary = 'Turn workforce management goals into a complete, build-ready blueprint: role-based journeys, scheduling logic, integration specifications, and an adoption plan your delivery teams can execute without ambiguity.',
  overview_paragraphs = '["The Workforce Management Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines workforce workflows and build-ready specifications.","Turn workforce management goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for hr, workforce planning & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate workforce management requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no build commitment required","Covers all workforce categories relevant to your organisation","Blueprint is system-agnostic and delivery-team ready"]'::jsonb,
  why_it_matters = '{"hook":"Workforce systems shape how you deploy talent, manage capacity, and respond to demand.","problemParagraph":"Many organisations buy workforce tools without designed scheduling models, policy rules, or specifications HR and operations teams can implement. This design engagement defines workforce workflows and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined scheduling models","description":"Rostering, skills matching, and approval flows are not designed end to end."},{"title":"Policy fragmentation","description":"Rules for overtime, leave, and compliance vary by site or manager."},{"title":"Integration ambiguity","description":"Teams lack specs for HRIS, payroll, and operations system connections."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned workforce designs","description":"Scheduling and capacity models reflect operational reality."},{"title":"Consistent policy standards","description":"Rules and controls are defined for governance and auditability."},{"title":"Implementation-ready specs","description":"Teams receive artefacts that accelerate workforce platform delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the workforce management design engagement.'
WHERE variant_id = 98;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Workforce journey maps', 'End-to-end flows for each role: how managers create rosters, how workers view and swap shifts, and how exceptions are handled.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Scheduling and rostering specification', 'Rules, constraints, and business logic documented so development or configuration teams can build without interpretation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Integration design', 'Data flows, field mappings, and API or file-exchange patterns for every connected system including payroll and HRIS.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (98, 'Adoption and change plan', 'Phased rollout approach, training requirements by role, and success metrics to track uptake after launch.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'Does the design tie us to a specific platform?', 'No. The DigitalQatalyst team designs to your requirements first. Platform selection is informed by the design, not the other way around.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'What if we already have a platform in place?', 'We design around it, documenting configuration changes, integration updates, and any gaps the current platform cannot close.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'How do frontline workers feed into the design?', 'We include representative users in journey workshops to ensure scheduling and communication flows work for the people using them daily.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (98, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the workforce categories in scope and the systems we need to design around before the engagement begins.', 3);

-- Workforce Management (High-Impact) - AI Design (variant 99)
UPDATE product_content SET
  description = 'Validate where AI can improve scheduling accuracy, demand forecasting, and workforce coordination before committing build budget. The DigitalQatalyst team produces responsible workflow designs and deployment-ready specifications for every approved use case.',
  positioning = 'Define and validate the AI use cases that will actually improve workforce management, with guardrails built in from the start.',
  hero_summary = 'Validate where AI can improve scheduling accuracy, demand forecasting, and workforce coordination before committing build budget. The DigitalQatalyst team produces responsible workflow designs and deployment-ready specifications for every approved use case.',
  overview_paragraphs = '["The Workforce Management AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for workforce management, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for hr, workforce planning & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for workforce management.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Validates feasibility before any build investment is committed","Responsible AI by design: bias controls and override paths included","Covers scheduling, forecasting, and absence management use cases"]'::jsonb,
  why_it_matters = '{"hook":"Workforce systems shape how you deploy talent, manage capacity, and respond to demand.","problemParagraph":"Many organisations apply AI to your workforce systems without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for workforce management lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for workforce management are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the workforce management AI design engagement.'
WHERE variant_id = 99;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'AI use-case feasibility register', 'Each candidate use case scored against data availability, technical complexity, and business value, with a go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Data readiness report', 'Gaps in training data, labelling, and integration coverage that must be closed before model development can begin.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Responsible workforce AI workflows', 'Designed flows for approved use cases including human override points, fairness constraints, and worker-facing explainability.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (99, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, drift detection triggers, and retraining schedules for production readiness.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'Which AI use cases are typically in scope?', 'Demand-based auto-rostering, absence and attrition prediction, shift-swap optimisation, and fatigue or compliance flagging are the most common starting points.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'What if our workforce data is incomplete?', 'The data readiness report identifies exactly what is missing. Many organisations begin with narrower use cases while filling data gaps in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'How do you address fairness in scheduling AI?', 'Fairness constraints, protected-attribute exclusions, and worker-facing explanations are built into the workflow design, not added later.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (99, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and confirm your current data landscape.', 3);

