  overview_paragraphs = '["The Enterprise Data Platform Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed enterprise data platform changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated enterprise data platform assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pipeline acceptance criteria agreed before build begins, so there is no ambiguity at launch","Parallel running period built in to confirm data fidelity before full cutover","Runbooks and handover materials produced as part of the engagement, not as an afterthought"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations stall between approved designs and production for your enterprise data platform, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for enterprise data platform sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform deployment engagement.'
WHERE variant_id = 106;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Configured and tested data platform', 'A fully provisioned platform environment with all agreed pipelines live, tested against acceptance criteria, and confirmed ready for production traffic.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Integration test results and sign-off', 'Test evidence covering each source-to-destination data flow, with defects resolved and results signed off by your technical lead.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Operations runbook set', 'Step-by-step runbooks for pipeline monitoring, incident triage, scheduled maintenance, and common failure scenarios.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Handover and knowledge transfer pack', 'Session recordings, architecture documentation, and a competency checklist confirming your team can operate the platform independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What does the knowledge transfer programme involve in practice?', 'Your operations and engineering teams join live sessions covering platform monitoring, pipeline triage, and incident response. They receive runbooks, architecture documentation, and a sign-off checklist before the DigitalQatalyst team steps back.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do you handle data quality during migration?', 'We define acceptance criteria for each pipeline before build. During testing, every pipeline output is validated against those criteria. Any deviation is classified and resolved before that pipeline goes live.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What if a source system integration is more complex than expected?', 'Scope changes are assessed formally. The DigitalQatalyst team will identify the impact on timeline and budget and agree any adjustment with you before proceeding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do we get started?', 'The deployment engagement follows directly from a completed design. Share your architecture blueprint with the DigitalQatalyst team and we will confirm scope, resourcing, and a kick-off date.', 3);

-- Enterprise Data Platform (High-Impact) - AI Deploy (variant 107)
