  deliverables_summary = '["This engagement deploys production AI capabilities for enterprise data platform with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Governance and monitoring configured before go-live, not retrofitted after an incident","Rollback capability tested and confirmed before any model goes live in production","Handover includes retraining triggers and a model lifecycle management guide"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many AI initiatives for your enterprise data platform fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for enterprise data platform fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform AI deployment engagement.'
WHERE variant_id = 107;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Production AI deployment', 'AI models serving live predictions via governed endpoints, with version control, rollback capability, and environment isolation confirmed working.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Monitoring and alerting configuration', 'Drift detection, performance dashboards, and alert thresholds configured so your team knows immediately when a model needs attention.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Governance and audit controls', 'Audit logs, prediction traceability records, and access control configurations meeting your compliance and responsible AI requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'ML operations handover pack', 'Incident playbooks, retraining triggers, monitoring guides, and a sign-off checklist confirming your ML team can operate and maintain the models independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What does model drift monitoring look like?', 'We configure statistical checks on input feature distributions and prediction output distributions. When either drifts beyond agreed thresholds, your team receives an alert and the incident playbook tells them what to investigate first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do you handle model versioning in production?', 'Every model version is tagged, stored in a model registry, and deployed with a documented rollback path. Promoting a new version requires a passing validation suite, so production is never overwritten without evidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What if a model underperforms in production?', 'The incident playbook covers this. Your team can roll back to the previous version immediately. The DigitalQatalyst team will support a root-cause review if the underperformance is not explained by drift.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do we get started?', 'The AI deployment engagement follows from a completed AI design. Share your deployment specifications with the DigitalQatalyst team and we will confirm scope, ML infrastructure requirements, and a timeline.', 3);

-- Enterprise Data Platform (High-Impact) - Managed (variant 108)
UPDATE product_content SET
  description = 'Keep your enterprise data platform running, governed, and improving every month, with SLA-backed pipeline monitoring, incident response, data quality reporting, and continuous optimisation by the DigitalQatalyst team.',
  positioning = 'Keep your data platform trusted and performant every month, with proactive monitoring, rapid incident resolution, and a continuous improvement cycle built into the service.',
  hero_summary = 'Keep your enterprise data platform running, governed, and improving every month, with SLA-backed pipeline monitoring, incident response, data quality reporting, and continuous optimisation by the DigitalQatalyst team.',
  overview_paragraphs = '["The Enterprise Data Platform Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve enterprise data platform with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for enterprise data platform - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed incident response with defined detection and resolution time targets","Monthly quality reporting gives leadership a consistent view of platform health","Optimisation reviews prevent cost and performance drift over time"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations struggle to sustain performance across your enterprise data platform after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"enterprise data platform issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform managed service.'
WHERE variant_id = 108;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Monthly data quality report', 'A scored view of platform data quality across completeness, accuracy, freshness, and lineage, with trend analysis and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Incident log and resolution record', 'A complete log of every pipeline incident, the time to detect and resolve, the root cause, and the preventive action taken.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Quarterly performance and cost review', 'An analysis of platform query performance, compute and storage costs, and the optimisations applied or recommended for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Governance compliance summary', 'A periodic report confirming that access controls, lineage coverage, and data retention policies remain compliant with your governance framework.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What SLAs apply to the managed service?', 'SLAs are agreed during onboarding and typically cover time to detect a pipeline failure, time to notify, and time to resolve by severity level. Your account is reviewed against these targets in the monthly report.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What happens when a pipeline fails?', 'The DigitalQatalyst team receives an alert, assesses severity, and begins remediation within the agreed response window. You are notified immediately and kept updated until resolution.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'Can we request changes or new pipelines under the managed service?', 'Yes. Change requests are scoped and delivered within the service. Larger changes that exceed the included capacity are quoted separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'How do we get started?', 'The managed service typically follows a completed deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs, and schedule the onboarding period.', 3);

